SELECT p.item_number, p.description, p.manufacturer, oi.quantity
FROM products p
JOIN order_items oi ON p.product_id = oi.product_id;

SELECT MAX(max_temperature) 
FROM products 
WHERE manufacturer = 'Company A' AND category_id = 2;

SELECT product_id
FROM inventory
WHERE quantity = (SELECT MAX(quantity) FROM inventory);
